import React, { useState } from 'react';
import TaskCard from '../components/TaskCard';
import AddTaskModal from '../components/AddTaskModal';
import './TasksPage.css';

const STATUS_FILTERS = [
  { value: 'all',         label: 'Tất cả'          },
  { value: 'pending',     label: 'Chưa hoàn thành' },
  { value: 'in_progress', label: 'Đang thực hiện'  },
  { value: 'completed',   label: 'Đã hoàn thành'   },
];

export default function TasksPage({ tasks, onAdd, onUpdate, onDelete, onStatusChange, openModal, setOpenModal }) {
  const [filterStatus, setFilterStatus] = useState('all');
  const [filterSubject, setFilterSubject] = useState('all');
  const [editTask, setEditTask] = useState(null);

  const subjects = ['all', ...new Set(tasks.map(t => t.subject))];

  const filtered = tasks.filter(t => {
    const matchStatus  = filterStatus === 'all'  || t.status === filterStatus;
    const matchSubject = filterSubject === 'all' || t.subject === filterSubject;
    return matchStatus && matchSubject;
  });

  function handleSave(form) {
    if (editTask) {
      onUpdate(editTask.id, form);
    } else {
      onAdd(form);
    }
    setEditTask(null);
  }

  function handleEdit(task) {
    setEditTask(task);
    setOpenModal(true);
  }

  function handleClose() {
    setOpenModal(false);
    setEditTask(null);
  }

  return (
    <div className="page-container animate-fade-in">
      {/* Page Header */}
      <div className="page-header">
        <div className="page-title">
          <h1>📋 Bài tập</h1>
          <p>Tổng cộng <strong style={{ color: 'var(--text-primary)' }}>{tasks.length}</strong> bài tập · <strong style={{ color: 'var(--accent-blue-light)' }}>{filtered.length}</strong> đang hiển thị</p>
        </div>
      </div>

      {/* Filters */}
      <div className="tasks-filters">
        <div className="filter-group">
          <span className="filter-label">Trạng thái:</span>
          {STATUS_FILTERS.map(f => (
            <button
              key={f.value}
              className={`filter-btn ${filterStatus === f.value ? 'filter-btn--active' : ''}`}
              onClick={() => setFilterStatus(f.value)}
            >
              {f.label}
            </button>
          ))}
        </div>

        <div className="filter-group">
          <span className="filter-label">Môn học:</span>
          <select
            className="form-select filter-select"
            value={filterSubject}
            onChange={e => setFilterSubject(e.target.value)}
          >
            {subjects.map(s => (
              <option key={s} value={s}>{s === 'all' ? 'Tất cả môn' : s}</option>
            ))}
          </select>
        </div>
      </div>

      {/* Task List */}
      {filtered.length === 0 ? (
        <div className="empty-state">
          <div className="empty-state-icon">📭</div>
          <h3>Không có bài tập nào</h3>
          <p>Thay đổi bộ lọc hoặc thêm bài tập mới để bắt đầu</p>
        </div>
      ) : (
        <div className="tasks-grid">
          {filtered.map(task => (
            <TaskCard
              key={task.id}
              task={task}
              onStatusChange={onStatusChange}
              onDelete={onDelete}
              onEdit={handleEdit}
            />
          ))}
        </div>
      )}

      {/* Modal */}
      <AddTaskModal
        open={openModal}
        onClose={handleClose}
        onSave={handleSave}
        editTask={editTask}
      />
    </div>
  );
}
